/* ── DATA MODEL ──────────────────────────────────────────────────────────── */
const gid=()=>Date.now()+Math.floor(Math.random()*99999);
const mkAcct=(p={})=>({id:gid(),name:"",type:"checking",value:0,owner:"joint",...p});
const mkLoan=(p={})=>({id:gid(),name:"",type:"personal",balance:0,owner:"joint",apr:0,...p});
const mk=(p={})=>({id:Date.now()+Math.random(),firstName:"",lastName:"",partnerFirst:null,partnerLast:null,email:"",phone:"",address:"",dob:"",social:"",clientType:"financeOnly",recommendedBy:"",color1:"#4472C4",color2:"#ED7D31",efMonths:3,currentMonthLabel:"May 2026",incomeStreams:[],bills:[],cards:[],accounts:[],loans:[],customAssets:[],alloc:{stocks:25,retirement:20,realEstate:20,savings:15,vacation:10,other:10},portfolioCustom:{holdings:[],overrides:{},rates:{}},notes:{shortTerm:"",midTerm:"",longTerm:"",setbacks:"",goals:"",general:""},monthSnapshots:[],...p});

const migrateCard=c=>{if(Array.isArray(c.promos))return c;const promos=c.promo&&(+c.promoBalance||0)>0?[{id:gid(),label:"Promo",balance:+c.promoBalance||0,rate:+c.promoRate||0,end:c.promoEnd||""}]:[];return{...c,promos,promo:undefined,promoBalance:undefined,promoRate:undefined,promoEnd:undefined};};
const migrateAccounts=c=>{if(Array.isArray(c.accounts)&&c.accounts.length>0)return c.accounts;const a=c.assets||{};const r=[];if(a.checking>0)r.push(mkAcct({name:"Checking",type:"checking",value:a.checking,owner:"joint"}));if(a.savings>0)r.push(mkAcct({name:"Savings",type:"savings",value:a.savings,owner:"joint"}));if(a.retirement>0)r.push(mkAcct({name:"Retirement",type:"retirement",value:a.retirement,owner:"p1"}));if(a.vehicle>0)r.push(mkAcct({name:"Vehicle",type:"vehicle",value:a.vehicle,owner:"p1"}));if(a.realEstate>0)r.push(mkAcct({name:"Real Estate",type:"realEstate",value:a.realEstate,owner:"joint"}));return r;};
