function ResourcesPage({t}){const th=useTh();const guides=[{title:"Understanding Your Credit Score",desc:"How credit scores are calculated and actionable strategies to improve yours.",icon:"📊"},{title:"Debt Payoff Strategies",desc:"Avalanche vs. Snowball — which method is right for your situation.",icon:"📉"},{title:"Building an Emergency Fund",desc:"Why 3-6 months of expenses matters and how to build it fast.",icon:"🛡️"},{title:"Retirement Savings 101",desc:"Roth IRA, 401k, contribution strategies, and employer matching.",icon:"🎯"},{title:"First-Time Homebuyer Guide",desc:"Pre-approval, down payment, DTI requirements, and timing.",icon:"🏠"},{title:"Investment Allocation Basics",desc:"Risk tolerance, time horizon, and diversification principles.",icon:"📈"}];return<div style={{padding:24}}><h2 style={{fontSize:18,fontWeight:800,color:th.text,marginBottom:4,marginTop:0}}>📚 {t.resourcesTitle}</h2><p style={{fontSize:11,color:th.dim,marginBottom:16,marginTop:0}}>{t.resourcesDesc}</p><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>{guides.map(g=><div key={g.title} style={{...mCARD(th),padding:16}}><div style={{fontSize:28,marginBottom:8}}>{g.icon}</div><div style={{fontWeight:700,fontSize:13,color:th.text,marginBottom:6}}>{g.title}</div><div style={{fontSize:11,color:th.muted,lineHeight:1.6,marginBottom:12}}>{g.desc}</div><a href={`mailto:mauricio@goldenanchor.life?subject=Resource: ${g.title}`} style={{fontSize:11,padding:"4px 12px",borderRadius:6,background:th.accent+"22",color:th.accent,border:`1px solid ${th.accent}44`,cursor:"pointer",textDecoration:"none",fontWeight:600}}>{t.openGuide}</a></div>)}</div></div>;}
